// FRF race-speed benchmark — the speed-daemon impact of the ternary fork
// verdict over the legacy `sawRejection` boolean.
//
// HOT PATH: the swerve / distributed-inference fold gathers N partial results
// from mesh workers (the forks) and folds them. Workers fault or exhaust budget
// (a fork rejects). A consumer that needs a *complete* result must decide what
// to do when some forks reject.
//
// The boolean could only say "clean" vs "something rejected" — it could not tell
// partial-but-recoverable apart from total failure. A correctness-complete
// consumer built on that bool must RE-RUN THE WHOLE BATCH on any rejection, and
// keep re-running until a fully-clean pass (geometric in the failure rate).
//
// The trit (`verdict`: Accept / Abstain / Decline) restores the middle: on
// Abstain (partial survivors) the fold SHIPS now and a targeted backfill re-forks
// ONLY the failed slots. That is the race-speed payoff measured here.
//
// Both strategies are built on the REAL `forkRaceFold` from ../src/frf — only the
// consumer's reaction to the result differs. Wall-clock is real (the forks resolve
// after real sub-millisecond delays; `forkRaceFold` runs them concurrently via
// Promise.allSettled). The PRNG is seeded, so the work/round counts are exact and
// the assertions are deterministic.
//
// HONEST SCOPE: this measures the avoided-whole-batch-retry mechanism with a
// parameterized latency/failure model; it is not a production mesh A/B. The win
// is structural (binary rounds ~ 1/(1-p)^N vs ternary ~ 1 + backfill) and the
// sweep shows the scaling, not a single magic number.

import { describe, it, expect } from 'vitest';
import { forkRaceFold, type ForkTask } from '../src/frf';
import { isAccept, isDefer } from '@a0n/bitwise/triton-verdict';

// ---- deterministic PRNG (mulberry32) -------------------------------------
function mulberry32(seed: number): () => number {
  let a = seed >>> 0;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

const delay = (ms: number): Promise<void> =>
  new Promise((r) => setTimeout(r, ms));

interface TrialOutcome {
  forkWork: number; // total fork executions (mesh worker invocations)
  rounds: number; // distinct fold rounds (network round-trips)
  wallMs: number; // measured wall-clock
}

// One worker fork: resolves a partial result after a real latency, or rejects
// (fault / budget exhausted) — a rejecting worker still burns its latency first.
function makeFork(
  rng: () => number,
  failProb: number,
  baseMs: number,
): { fork: ForkTask<number>; willFail: boolean } {
  const willFail = rng() < failProb;
  const latency = baseMs + rng() * baseMs; // baseMs .. 2*baseMs
  const fork: ForkTask<number> = async () => {
    await delay(latency);
    if (willFail) throw new Error('worker-fault');
    return 1;
  };
  return { fork, willFail };
}

// TERNARY consumer: one fold; on Abstain (partial) backfill ONLY failed slots.
async function ternaryFold(
  rng: () => number,
  n: number,
  failProb: number,
  baseMs: number,
): Promise<TrialOutcome> {
  const t0 = performance.now();
  const built = Array.from({ length: n }, () => makeFork(rng, failProb, baseMs));
  let forkWork = n;
  let rounds = 1;
  const res = await forkRaceFold<number, number>({
    forks: built.map((b) => b.fork),
    fold: (xs) => xs.length,
  });
  if (isDefer(res.verdict)) {
    // Partial survivors: ship the fold, backfill the failed slots only.
    const failedCount = res.report.rejectedCount;
    forkWork += failedCount;
    rounds += 1;
    // Targeted re-fork of just the gap (assume the retry succeeds for the model).
    await forkRaceFold<number, number>({
      forks: Array.from({ length: failedCount }, () => async () => {
        await delay(baseMs + rng() * baseMs);
        return 1;
      }),
      fold: (xs) => xs.length,
    });
  }
  return { forkWork, rounds, wallMs: performance.now() - t0 };
}

// BINARY consumer: the bool only knows "any rejection" — to get a complete
// result it discards the run and RE-RUNS THE WHOLE BATCH until fully clean.
async function binaryFold(
  rng: () => number,
  n: number,
  failProb: number,
  baseMs: number,
  maxRounds = 60,
): Promise<TrialOutcome> {
  const t0 = performance.now();
  let forkWork = 0;
  let rounds = 0;
  for (; rounds < maxRounds; ) {
    const built = Array.from({ length: n }, () =>
      makeFork(rng, failProb, baseMs),
    );
    forkWork += n;
    rounds += 1;
    const res = await forkRaceFold<number, number>({
      forks: built.map((b) => b.fork),
      fold: (xs) => xs.length,
    });
    if (isAccept(res.verdict)) break; // fully clean batch — done.
    // else: sawRejection — the bool cannot use survivors; retry the whole batch.
  }
  return { forkWork, rounds, wallMs: performance.now() - t0 };
}

interface Row {
  n: number;
  p: number;
  tWork: number;
  bWork: number;
  tRounds: number;
  bRounds: number;
  tWall: number;
  bWall: number;
}

describe('FRF race-speed: ternary backfill vs binary whole-batch retry', () => {
  it('measures fork-work, rounds, and wall-clock across an N×failure sweep', async () => {
    const TRIALS = 60;
    const baseMs = 1.2;
    const Ns = [4, 8, 16];
    const Ps = [0.05, 0.1, 0.2];
    const rows: Row[] = [];

    for (const n of Ns) {
      for (const p of Ps) {
        // Separate seeded streams so ternary/binary see the same failure draws.
        const rngT = mulberry32(0x9e3779b9 ^ (n << 8) ^ (p * 1000));
        const rngB = mulberry32(0x9e3779b9 ^ (n << 8) ^ (p * 1000));
        let tWork = 0,
          bWork = 0,
          tRounds = 0,
          bRounds = 0,
          tWall = 0,
          bWall = 0;
        for (let i = 0; i < TRIALS; i++) {
          const t = await ternaryFold(rngT, n, p, baseMs);
          const b = await binaryFold(rngB, n, p, baseMs);
          tWork += t.forkWork;
          bWork += b.forkWork;
          tRounds += t.rounds;
          bRounds += b.rounds;
          tWall += t.wallMs;
          bWall += b.wallMs;
        }
        rows.push({
          n,
          p,
          tWork: tWork / TRIALS,
          bWork: bWork / TRIALS,
          tRounds: tRounds / TRIALS,
          bRounds: bRounds / TRIALS,
          tWall: tWall / TRIALS,
          bWall: bWall / TRIALS,
        });
      }
    }

    const f = (x: number) => x.toFixed(2).padStart(8);
    // eslint-disable-next-line no-console
    console.log(
      '\nFRF race-speed (mean over ' +
        TRIALS +
        ' trials, baseMs=' +
        baseMs +
        ')\n' +
        '  N    p   | fork-work tern/bin (x)  | rounds tern/bin | wall ms tern/bin (x)',
    );
    for (const r of rows) {
      const workX = r.bWork / r.tWork;
      const wallX = r.bWall / r.tWall;
      // eslint-disable-next-line no-console
      console.log(
        ` ${String(r.n).padStart(2)}  ${r.p.toFixed(2)} |` +
          `${f(r.tWork)}/${f(r.bWork)} (${workX.toFixed(2)}x) |` +
          `${f(r.tRounds)}/${f(r.bRounds)} |` +
          `${f(r.tWall)}/${f(r.bWall)} (${wallX.toFixed(2)}x)`,
      );
    }

    // Deterministic invariant: ternary never does more fork-work or more rounds
    // than binary; the gap widens with N and p (the whole-batch-retry blowup).
    for (const r of rows) {
      expect(r.tWork).toBeLessThanOrEqual(r.bWork);
      expect(r.tRounds).toBeLessThanOrEqual(r.bRounds);
    }
    // At the stressed corner the binary whole-batch retry must cost strictly more.
    const corner = rows.find((r) => r.n === 16 && r.p === 0.2)!;
    expect(corner.bWork).toBeGreaterThan(corner.tWork * 1.5);
  }, 60_000);
});
